import { writeOutput } from "./codegen";

const DOCS_URL = "https://docs.checkr.com/";
const PLACEHOLDER_VALUE = "CoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocal";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Checkr API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:checkr",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const checkrFirewall = {",
    '  name: "checkr",',
    '  description: "Checkr API",',
    "  placeholders: {",
    `    CHECKR_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.checkr.com/v1",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "${{ basic(secrets.CHECKR_TOKEN, \\"\\") }}",',
    "        },",
    "      },",
    "      permissions: [",
    "        {",
    '          name: "read",',
    '          description: "Read Checkr resources",',
    '          rules: ["GET /{path+}"],',
    "        },",
    "        {",
    '          name: "write",',
    '          description: "Create, update, and delete Checkr resources",',
    "          rules: [",
    '            "POST /{path+}",',
    '            "PUT /{path+}",',
    '            "PATCH /{path+}",',
    '            "DELETE /{path+}",',
    "          ],",
    "        },",
    "      ],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Checkr firewall config...");
  const ts = generateTypeScript();
  writeOutput("checkr", ts, import.meta.dirname);
}
